&lt;p style=&quot;line-height: 1.4;&quot;&gt;&lt;span style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;&lt;strong&gt;Role Type:&lt;/strong&gt; Full-Time&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
